"use client"
import { useState } from "react";

export default function register() {
    const [name, setName] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");

    async function handleRegister(e) {
        e.preventDefault();
        const res = await fetch("http://localhost:8080/users", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify({
                name: name,
                email: email,
                password: password,
            }),
        })

    }

    return (
        <div className="flex flex-col gap-4 justify-center items-center h-screen">
            <h1 className="text-2xl font-bold mb-4">Register</h1>
            <div className="flex flex-col gap-4 w-1/2">
                <form onSubmit={handleRegister} className="flex flex-col gap-4">
                    <label htmlFor="name">Name</label>
                    <input type="text" placeholder="Name" className="border border-gray-300 rounded-md px-4 py-2" value={name} onChange={(e) => setName(e.target.value)} />
                    <label htmlFor="email">Email</label>
                    <input type="email" placeholder="Email" className="border border-gray-300 rounded-md px-4 py-2" value={email} onChange={(e) => setEmail(e.target.value)} />
                    <label htmlFor="password">Password</label>
                    <input type="password" placeholder="Password" className="border border-gray-300 rounded-md px-4 py-2" value={password} onChange={(e) => setPassword(e.target.value)} />
                    <button type="submit" className="bg-blue-500 text-white px-4 py-2 rounded-md">Register</button>
                    <div className="flex flex-row gap-2">
                        <p className="text-gray-500">Already have an account?</p>
                        <Link className="text-blue-500 hover:underline" href="/login" >Login</Link>
                    </div>
                </form>
            </div>
        </div>
    );
}